{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class NoConsecutiveBlankLinesRuleReproductionTest {
    private val noConsecutiveBlankLinesRuleAssertThat = assertThatRule { NoConsecutiveBlankLinesRule() }

    @Test
    fun `Given a sealed class with consecutive blank lines at the end of the file`() {
        val code =
            """
            sealed class Hello


            """.trimIndent()
        val formattedCode =
            """
            sealed class Hello

            """.trimIndent()
        noConsecutiveBlankLinesRuleAssertThat(code)
            .hasLintViolation(2, 1, "Needless blank line(s)")
            .isFormattedAs(formattedCode)
    }
}
","file_path":"ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/NoConsecutiveBlankLinesRuleReproductionTest.kt"}

